module RefModule(  
    input wire clk,  
    input wire reset,  
    output reg out  
);  
    reg [2:0] obf_count; // 3-bit counter for counts from 0 to 7  

    always @(posedge clk or posedge reset) begin  
        if (reset) begin  
            obf_count <= 3'b000;  
            out <= 1'b0;  
        end else begin  
            if (obf_count == 3'b111) begin  
                obf_count <= 3'b000;  
                out <= ~out; // Toggle the output  
            end else begin  
                obf_count <= obf_count + 1;  
            end  
        end  
    end  
endmodule
